import java.io.*;

public class CommandInjectionSecure {

    public static void main(String[] args) {
        try {
            BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter a file name to display: ");
            String fileName = br.readLine();

            // Sanitize the input by allowing only alphanumeric characters and periods
            if (!fileName.matches("[a-zA-Z0-9\\.]+")) {
                throw new IllegalArgumentException("Invalid file name");
            }

            // Properly escape the file name to prevent command injection
            String escapedFileName = "\"" + fileName.replace("\"", "\\\"") + "\"";

            String[] command = {"cat", escapedFileName};

            Process process = new ProcessBuilder(command).start();

            BufferedReader reader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;

            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }

        } catch (IOException | IllegalArgumentException e) {
            e.printStackTrace();
        }
    }
}

